#include <stdio.h>
#include <string.h>

int isPalindrome(char *str) {
    int start = 0;
    int end = strlen(str) - 1;
    while (start < end) {
        if (str[start] != str[end]) {
            return 0;
        }
        start++;
        end--;
    }
    return 1;
}

int minDeletions(char **strs, int N) {
    int minDeletions = N;
    for (int i = 0; i < (1 << N); i++) {
        char concatenatedStr[1000] = "";
        int numDeletions = 0;
        for (int j = 0; j < N; j++) {
            if ((i & (1 << j)) == 0) {
                strcat(concatenatedStr, strs[j]);
            } else {
                numDeletions++;
            }
        }
        if (isPalindrome(concatenatedStr)) {
            minDeletions = (minDeletions < numDeletions) ? minDeletions : numDeletions;
        }
    }
    return minDeletions;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char **strs = (char **)malloc(N * sizeof(char *));
        for (int i = 0; i < N; i++) {
            strs[i] = (char *)malloc(3 * sizeof(char));
            scanf("%s", strs[i]);
        }
        printf("%d\n", minDeletions(strs, N));
        for (int i = 0; i < N; i++) {
            free(strs[i]);
        }
        free(strs);
    }
    return 0;
}

