import java.util.Scanner;
public class Main {
    public static boolean isPalindrome(String str) {
        int start = 0;
        int end = str.length() - 1;
        while (start < end) {
            if (str.charAt(start) != str.charAt(end)) {
                return false;
            }
            start++;
            end--;
        }
        return true;
    }

    public static int minDeletions(String[] strs, int N) {
        int minDeletions = N;
        for (int i = 0; i < (1 << N); i++) {
            StringBuilder concatenatedStr = new StringBuilder();
            int numDeletions = 0;
            for (int j = 0; j < N; j++) {
                if ((i & (1 << j)) == 0) {
                    concatenatedStr.append(strs[j]);
                } else {
                    numDeletions++;
                }
            }
            if (isPalindrome(concatenatedStr.toString())) {
                minDeletions = (minDeletions < numDeletions) ? minDeletions : numDeletions;
            }
        }
        return minDeletions;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            String[] strs = new String[N];
            for (int i = 0; i < N; i++) {
                strs[i] = scanner.next();
            }
            System.out.println(minDeletions(strs, N));
        }
        scanner.close();
    }
}

